export const category = "system_design_extras";
export const questions = [{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"设计分布式锁服务","content":"请设计一个高可靠的分布式锁服务，对比基于 Redis 和 ZooKeeper 的实现方案。","answer":"答案：分布式锁核心是互斥 + 可重入 + 容错\n\n解析：Redis 实现：SET key uuid NX PX 30000 加锁，Lua 脚本释放。优点：性能高、简单。缺点：主从切换可能丢失锁、没有自带续期机制。ZooKeeper 实现：创建临时顺序节点，监听前一个节点释放后获取锁。优点：强一致性、自带监听机制。缺点：性能低于 Redis、羊群效应。Redlock 算法：向大多数 Redis 节点同时申请锁，超过半数成功才算加锁成功，解决 Redis 单点问题但对时钟敏感。\n\n扩展延伸：续期机制：Redis 用 Watch Dog（守护线程在锁过期前续期）；ZK 无需续期（临时节点与会话绑定，会话断开自动释放）。可重入：加锁时记录线程身份和重入计数。公平锁 vs 非公平锁：ZK 天然公平（排队），Redis 需额外有序集合实现。最佳实践：业务场景容忍短暂不一致用 Redis，要求严格一致性用 ZK。","hints":["Redis 主从切换导致锁丢失怎么解决","Redlock 算法的争议点是什么"],"tags":["分布式","锁","一致性"],"id":5026},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"设计全局排行榜系统","content":"请设计一个支持亿级用户的实时全局排行榜系统。","answer":"答案：实时排行榜核心是高效的数据结构 + 分片 + 缓存\n\n解析：核心数据结构：Redis ZSet 是有序集合，基于跳表 + 哈希表实现，支持 O(log N) 的插入和范围查询。单 ZSet 理论可存上亿成员（需足够内存），写入压力大时需分片。分片策略：按用户 ID 哈希分到多个 ZSet 实例，查询全局排行时需合并结果。更新时间：用户在游戏/活动结束后更新，而非每次操作都更新。近似排行：对要求不高的场景，可用近似排行（布隆过滤器估算位数 + 概率性排序）。\n\n扩展延伸：实时 vs 准实时：全局排行允许数分钟延迟，用离线计算（MapReduce/Spark）+ Redis 缓存结果。榜单类型：积分榜、段位榜、社交榜（好友排名用 ZInterStore 取交集）。历史榜单归档：按赛季/时间段存储快照到 MySQL/HBase。防止刷榜：限制更新频率限流、数据校验、异常行为检测。ZSet 的 skip list 实现中，每个节点维护多层指针，平均层数约 1.33，插入时通过随机层数决策保证平衡。","hints":["上亿用户用单 ZSet 有哪些风险","多分片的全局排行如何合并"],"tags":["分布式","排行榜","Redis"],"id":5027},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"多租户 SaaS 系统设计","content":"请设计一个多租户 SaaS 系统，支持资源隔离、租户定制和弹性扩缩。","answer":"答案：多租户核心是隔离模式 + 租户上下文 + 计量计费\n\n解析：隔离模式：1）Database per Tenant — 隔离性最好、备份恢复独立，适合大客户但每个租户一个 DB 运维成本高 2）Schema per Tenant — 共享数据库独立 Schema 3）Shared Table — 通过 tenant_id 列隔离，成本最低但数据恢复困难。数据库中间件层支持连接路由（根据租户 ID 选择 DB/Schema）。应用层：上下文透传（Token/Header 中的 tenant_id），租户定制通过元数据配置表而非硬编码。\n\n扩展延伸：租户资源限制：按租户级别做限流（令牌桶）、配额管理（API 调用次数、存储空间上限）。弹性：K8s HPA 根据整体负载自动扩缩。数据迁移：租户从共享表升级到独立 DB（数据迁移 + DNS 切换）。计量计费：实时采集租户资源使用量（API 调用量、存储量），写入时序库，定时结算。SaaS 成熟度模型 Level 1-4：从单租户单实例到多租户弹性平台。","hints":["三种隔离模式各自的运维复杂度差异","租户升级迁移时如何保证数据不丢失"],"tags":["SaaS","多租户","架构"],"id":5028},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"设计实时协同编辑系统","content":"请设计一个支持多人实时协同编辑的系统（类似 Google Docs），重点说明冲突解决策略。","answer":"答案：协同编辑核心是 OT 或 CRDT 算法 + WebSocket 通信\n\n解析：操作转换（OT）是 Google Docs 使用的经典方案，每个操作移动光标位置，服务端维护操作版本号，并发操作发生时对操作进行转换使其在各自文档上下文中语义正确。OT 难点在于正确实现所有操作类型的转换函数（insert/delete/format）。CRDT（无冲突可复制数据类型）则通过数据结构设计使并发写入天然可合并，不需要中心化转换。Yjs 的实现基于 CRDT，每个字符携带唯一 ID（客户端 ID + 逻辑时钟），在本地排序后合并。\n\n扩展延伸：通信架构通过 WebSocket 建立长连接，操作以批处理方式同步（按一定间隔或操作数合并发送以减少网络开销）。文本选区（Selection/Cursor）同步通过广播位置信息实现。服务端存储全量操作日志（Operation Log）用于回放和历史回溯。离线编辑：本地积累操作，联网后批量同步合并。性能关键：避免不必要的全量 diff，增量更新操作序列即可。Google Docs 使用 OT + 服务端集中式架构，VS Code Live Share 使用 CRDT。","hints":["OT 和 CRDT 的核心区别是什么","协同编辑中的光标位置怎么同步"],"tags":["协同","实时","CRDT","OT"],"id":5029},{"category":"system_design_extras","difficulty":"medium","type":"short_answer","title":"设计功能开关/特性标记系统","content":"请设计一个功能开关（Feature Flag/Feature Toggle）系统，支持灰度发布、A/B 测试和动态配置。","answer":"答案：特性标记系统核心是标记管理 + 目标匹配 + 动态生效\n\n解析：标记存储使用分布式配置中心（如 Nacos/etcd）保存标记规则，支持结构化配置（JSON/YAML）。目标匹配规则包括：按用户 ID（范围/白名单）、按百分比、按地域/客户端版本/设备类型等属性。标记评估在客户端或服务端完成：1）服务端评估 — 统一规则，安全性高，但延迟较高 2）客户端评估 — 缓存标记规则到本地，毫秒级响应，适合移动端。架构采用 SDK（集成到业务应用）+ 管理后台（可视化标记管理面板）+ 存储层。\n\n扩展延伸：标记的推出策略：ops 操作（百分比递增发布，从 1% -> 5% -> 50% -> 100%），自动回滚（监控到错误率上升自动关闭标记）。标记生命周期：创建 -> 评估 -> 稳定 -> 清理（技术债务：长期不清理的标记累积增加代码复杂度）。LaunchDarkly 商业方案的核心：流式（Streaming）推送规则变化，SDK 连接流通道实时接收更新。多环境管理：dev/staging/production 每个环境独立标记值。","hints":["功能标记长期不清理会有什么问题","客户端评估和服务端评估各有什么优缺点"],"tags":["特性标记","灰度发布","A/B测试"],"id":5030},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"Raft 协议：Leader 选举与日志复制","content":"请介绍 Raft 共识协议的 Leader 选举过程和日志复制机制。","answer":"答案：Raft 是一种易于理解的分布式共识协议，通过 Leader 选举和日志复制保证集群一致性。\n\n节点状态：\n1. Leader（领导者）：处理客户端请求，管理日志复制\n2. Follower（跟随者）：被动响应 Leader 和 Candidate 的请求\n3. Candidate（候选者）：竞选下一任 Leader\n\nLeader 选举：\n\n触发条件：\n- Follower 在 Election Timeout（随机 150~300ms）内未收到 Leader 的 AppendEntries\n\n选举过程：\n1. Follower → Candidate：\n   - 增加 currentTerm\n   - 给自己投票\n   - 向其他节点发送 RequestVote RPC\n2. Candidate 获胜条件：\n   - 获得大多数节点（N/2+1）投票\n   - 同一 Term 内每个节点最多投一票\n3. 如果多个 Candidate 同时参选（Split Vote）：\n   - 没有人获得大多数\n   - 等待随机 Election Timeout 后重新发起选举\n4. 新 Leader 上任：\n   - 立即发送 AppendEntries（心跳）通知其他节点\n   - 建立新的 Term\n\n日志复制：\n\n流程：\n1. 客户端请求 → Leader\n2. Leader 追加日志到本地日志\n3. Leader 并行发送 AppendEntries RPC 到所有 Follower\n4. 日志提交条件：\n   - Leader 确认日志被复制到多数节点\n   - Leader 将该日志标记为 committed\n   - 应用到状态机（apply）\n5. Leader 在下一个 AppendEntries（或心跳）通知 Follower 提交\n\n日志一致性保证：\n- 如果两个日志条目有相同的 term 和 index，则它们的内容相同（Leader 在给定 term 和 index 最多创建一条日志）\n- 如果日志条目在给定 index 已提交，则所有之前的日志条目都已提交\n\n安全性（Safety）：\n- Leader 完整性：如果一个日志条目在某个 term 提交，它一定存在于所有后续 term 的 Leader 中\n- 选举限制：Candidate 的日志必须至少跟大多数节点一样新（否则无法当选）\n- 只有当前 term 的日志条目通过提交计数（多数复制）来决定是否提交\n\n扩展延伸：Raft 的简化体现在 Leader 强约束——所有日志流都经过 Leader，简化了共识逻辑但牺牲了写吞吐（所有写请求经过单一 Leader）。读优化：Raft 支持 ReadIndex（Leader 确认自己仍是 Leader 后直接在本地读）和 Lease Read。","hints":["选举：随机超时（150-300ms）→ Candidate → 多数投票获胜 → 定期心跳维持任期","日志复制：Leader 追加 → 并行复制到 Follower → 多数提交 → 应用到状态机","安全性：日志只能从 Leader 到 Follower（单向），新 Leader 必须日志最新"],"tags":["系统设计","Raft","共识","分布式系统"],"id":5037},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"CQRS 与事件源架构","content":"请介绍 CQRS（命令查询职责分离）和事件源（Event Sourcing）架构的设计思路及其配合使用的方式。","answer":"答案：CQRS 和事件源是两种可以独立使用但经常配合的架构模式。\n\nCQRS（Command Query Responsibility Segregation）：\n\n核心思想：\n- 将读操作（Query）和写操作（Command）分离到不同的模型\n- 命令（Command）：改变状态的请求（返回状态码而非数据）\n- 查询（Query）：读取状态的请求（不改变状态）\n\n设计要点：\n- 命令模型针对写优化（强一致、完整性约束）\n- 查询模型针对读优化（反范式、投影表、缓存友好）\n- 命令和查询可以有不同的数据存储（甚至不同数据库类型）\n- 读写之间的数据同步通过异步机制（事件、消息队列）\n\n适用场景：\n- 读操作远多于写操作（如内容系统）\n- 读写负载差异大（如写 TPS 高但读需要毫秒响应）\n- 复杂领域逻辑需要专门的写模型\n\n不适用场景：\n- 简单的 CRUD（只有一个模型就够了）\n- 对一致性要求极高的系统\n\n事件源（Event Sourcing）：\n\n核心思想：\n- 不存储当前状态，而是存储所有状态变更事件\n- 当前状态 = 对所有事件的归约（Replay）\n- 事件是不可变的、追加写入的日志\n\n设计要点：\n- Event Store：专用的事件存储（如 EventStoreDB、基于 Kafka 实现）\n- 事件是业务事实（如 OrderPlaced、PaymentReceived）\n- 快照（Snapshot）：定期对事件做归约，避免每次从头回放\n- 投影（Projection）：从事件流构建查询模型\n\n优势：\n- 完整的审计日志（事件不可变）\n- 时间旅行（回到任意历史状态）\n- 松耦合（事件发布，消费者独立定义投影）\n\nCQRS + Event Sourcing 的组合：\n\n典型架构：\n1. 命令端：验证命令 → 生成事件 → 写入 Event Store\n2. 事件总线：发布事件到 MQ / Stream\n3. 投影端：消费事件，构建查询数据库（可以是 Redis、ES、MySQL 等）\n4. 查询端：从查询数据库读取，返回给客户端\n\n优势叠加：\n- 写路径：Event Store（完美追加性能）\n- 读路径：自定义投影（查询优化、缓存友好）\n- 扩展性：读/写独立扩缩容\n\n挑战：\n- 最终一致性（写入事件到查询可见有时间差）\n- Event Store 的运维复杂度\n- 事件模式演进难（事件是不可变的）\n\n扩展延伸：CQRS 不必须配合 Event Sourcing。可以只用 CQRS（读写分离的数据源）不用 Event Sourcing，也可以只用 Event Sourcing 不用 CQRS。两者配合是最强组合但也是最高复杂度。","hints":["CQRS：读写分离为不同模型（命令模型强一致，查询模型反范式），可异步同步","事件源：存储事件序列而非当前状态，通过事件回放恢复状态","组合：命令→事件→投影（构建查询视图）→查询。最灵活但复杂度最高"],"tags":["系统设计","CQRS","Event Sourcing","架构模式"],"id":5038},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"漏斗分析方法与 SQL 实现","content":"如何用 SQL 高效实现用户转化漏斗分析？请介绍几种常见的漏斗实现方案。","answer":"答案：用户漏斗分析是产品分析的常用方法，SQL 实现方案取决于数据规模和实时性要求。\n\n方案一：基于时间窗口的条件累加（简单漏斗）\n\n适用场景：少量步骤（3-5步），事件时间有序\n\n```sql\nSELECT\n    COUNT(DISTINCT CASE WHEN step1_time IS NOT NULL THEN user_id END) AS step1,\n    COUNT(DISTINCT CASE WHEN step2_time IS NOT NULL THEN user_id END) AS step2,\n    COUNT(DISTINCT CASE WHEN step3_time IS NOT NULL THEN user_id END) AS step3\nFROM (\n    SELECT\n        user_id,\n        MIN(CASE WHEN event = 'page_view' THEN time END) AS step1_time,\n        MIN(CASE WHEN event = 'click_button' THEN time END) AS step2_time,\n        MIN(CASE WHEN event = 'submit_form' THEN time END) AS step3_time\n    FROM events\n    WHERE event IN ('page_view', 'click_button', 'submit_form')\n    GROUP BY user_id\n) t\n```\n\n限制：只能处理线性漏斗，不能保证步骤顺序\n\n方案二：基于窗口函数的漏斗（Flink 风格）\n\n```sql\nSELECT\n    level,\n    COUNT(DISTINCT user_id) AS users\nFROM (\n    SELECT\n        user_id,\n        SUM(CASE\n            WHEN event = 'step1' AND prev_event IS NULL THEN 1\n            WHEN event = 'step2' AND prev_event = 'step1' THEN 1\n            WHEN event = 'step3' AND prev_event = 'step2' THEN 1\n            ELSE 0\n        END) OVER (PARTITION BY user_id ORDER BY time) AS level\n    FROM events\n) t\nWHERE level > 0\nGROUP BY level\n```\n\n方案三：用 ClickHouse 的 windowFunnel 函数\n\nClickHouse 内置了漏斗函数：\n```sql\nSELECT\n    level,\n    count() AS users,\n    round(users / first_value(users) OVER (ORDER BY level), 2) AS conversion_rate\nFROM (\n    SELECT\n        user_id,\n        windowFunnel(86400)(time, event = 'step1', event = 'step2', event = 'step3') AS level\n    FROM events\n    GROUP BY user_id\n)\nGROUP BY level\n```\n\n实际生产方案：\n1. 实时漏斗（Flink SQL）：在流上计算窗口函数\n2. 离线漏斗（Spark/Hive）：每日汇总到漏斗结果表\n3. 预聚合（Druid / ClickHouse）：物化视图\n\n扩展延伸：漏斗分析的关键设计点——时间窗口（用户完成整个漏斗的最长时间）、步骤顺序（严格线性 vs 跳步允许）、去重策略（用户粒度 vs session 粒度）。推荐用 ClickHouse 或 Druid 等 OLAP 引擎做漏斗，在大规模数据上性能差距很大。","hints":["简单漏斗：Group By 用户 + MIN CASE WHEN，适合 3-5 步的顺序事件","窗口函数漏斗：基于 OVER PARTITION BY 计算步骤，控制步骤连续性","生产方案：Flink 做实时、Spark 做离线、ClickHouse 做 ad-hoc 查询"],"tags":["系统设计","漏斗分析","SQL","数据分析"],"id":5039},{"category":"system_design_extras","difficulty":"medium","type":"short_answer","title":"Gossip 协议原理与应用","content":"请介绍 Gossip 协议的核心原理及其在分布式系统中的应用。","answer":"答案：Gossip 协议是一种去中心化的节点间通信协议，用于信息传播和状态同步。\n\n核心原理：\n\n节点交互方式：\n1. Push：节点 A 将信息推送给随机选择的 B\n2. Pull：节点 A 向随机选择的 B 拉取信息\n3. Push-Pull：A 与 B 交换各自缺失的信息（最常用）\n\n传播机制：\n- 每个周期，节点随机选择 f 个其他节点\n- 交换各自已知的最新信息\n- 收到新信息的节点会在下一周期继续传播\n\n收敛特性：\n- 反熵（Anti-Entropy）：节点间的状态差异指数级减少\n- 传播速度：指数级扩散（类似病毒传播）\n- 在足够多的周期后，所有节点最终会收到信息\n\n容错性：\n- 节点故障不影响整体收敛性\n- 只要至少一个节点存活且网络部分连通，信息就能传播\n- 节点加入/离开不需要特殊处理\n\n应用场景：\n1. 服务发现：Consul（使用 SWIM gossip 协议）\n   - 节点间通过 Gossip 传播成员变更\n   - 分布式健康检查\n2. 分布式数据库节点同步：Cassandra、DynamoDB\n   - 节点间的元数据同步\n   - Hinted Handoff 的传播\n3. 集群故障检测：\n   - 通过超时和间接健康检查\n\nGossip vs 中心化方案：\n| 维度 | Gossip | 中心化（ZK/Etcd） |\n|------|--------|-------------------|\n| 一致性 | 最终一致 | 强一致 |\n| 可用性 | 高（去中心化） | 中（Leader 依赖） |\n| 复杂度 | 实现复杂 | 部署简单 |\n| 规模 | 适合大规模 | 适合小规模 |\n\n扩展延伸：SWIM 是 Gossip 的增强版，加入了 Ping/PingReq 间接探测机制和 Suspicion 机制（延迟判定节点死亡，避免误判）。Consul 的 Serf 底层使用 SWIM。","hints":["去中心化通信：每个周期随机选节点交换信息，指数级传播","反熵：节点间差异指数减少，最终所有节点收到","应用：Consul（服务发现）、Cassandra（元数据同步）、集群故障检测"],"tags":["系统设计","Gossip","分布式协议","一致性"],"id":5040},{"category":"system_design_extras","difficulty":"medium","type":"short_answer","title":"Redis 分布式锁的可靠性与 Redlock","content":"请分析基于 Redis 实现分布式锁的可靠性问题，并介绍 Redlock 算法的原理。","answer":"答案：Redis 分布式锁是最常用的分布式锁方案之一，但在可靠性方面存在一些争议。\n\n基础方案（单实例 SETNX）：\n- 加锁：SET key uuid NX PX 30000（原子操作）\n- 解锁：Lua 脚本验证 UUID 后 DEL（避免删别人的锁）\n- 问题：Redis 主从异步复制时，Master 宕机后锁可能丢失\n\n基础方案的风险：\n1. 锁丢失：Master 写入锁但未复制到 Slave 就宕机，新 Master 没有锁记录\n2. 锁超时：业务执行超过锁 TTL（需要在业务中检测续期）\n3. 时钟漂移：不同节点时钟不一致\n4. GC/Pause：业务线程 STW 超过锁有效期\n\nRedlock 算法：\n\n算法步骤：\n1. 记录当前时间 T1\n2. 串行向 N 个（通常 5 个）独立 Redis 实例获取锁\n   - 每个实例 SET key uuid NX PX <timeout>\n   - 每个实例的获取超时远小于锁 TTL（如 TTL=10s, 超时=50ms）\n3. 计算获取锁的总耗时：elapsed = T2 - T1\n4. 判断：如果 ≥ N/2+1 个实例成功 且 elapsed < TTL，则加锁成功\n5. 真正的锁有效期 = TTL - elapsed\n6. 如果失败，向所有实例发送解锁\n\nRedlock 的争议点：\n\nMartin Kleppmann（《DDIA》作者）的观点：\n- Redlock 不提供 fencing token，无法保证互斥\n- 解决方案：配合 fencing token 使用\n- 批评：分布式锁应该提供 lease（租约）语义，不是简单的过期\n\nRedis 作者 antirez 的反驳：\n- Fencing token 不是所有场景都需要\n- Redlock 在合理假设下可以工作\n- 如果时钟误差过大，任何分布式锁方案都会有问题\n\n实际生产建议：\n1. 对 Redis 分布式锁期望不要超过其能力范围\n2. 对于严格的互斥要求：使用 ZooKeeper / Etcd\n3. 无论如何锁设计，业务层做好幂等和补偿","hints":["基础问题：Redis 主从异步复制导致锁丢失，GC/Pause 导致锁超时被误释放","Redlock：向 N 个独立实例获取锁，多数成功才算加锁成功","核心争议：缺乏 fencing token，无法真正保证互斥"],"tags":["系统设计","分布式锁","Redis","Redlock"],"id":5041},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"多区域部署与异地容灾","content":"请设计一个多区域（Multi-Region）高可用部署方案，要求跨区域容灾。","answer":"答案：多区域高可用部署的核心挑战是跨区域延迟和最终一致性，需要合理的流量调度和数据同步策略\n\n解析：主流模式：1）Active-Passive（主备模式）— 一个 Region 处理所有写流量，备 Region 实时同步数据但不对外服务，主 Region 故障后手动/自动切到备 Region。写流量简单（单点写无冲突），但切换可能有分钟级延迟，且备 Region 资源利用率低。2）Active-Active（双活/多活）— 多个 Region 同时处理读写流量，通过 DNS 或 Global Load Balancer 路由用户到最近的 Region。需要解决跨 Region 的数据冲突问题——使用 CRDT 或无冲突方案，或按用户 ID 哈希分区（每个用户的写固定在一个 Region）。3）Read-Only Replicas（读写分离多区域）— 写在一个 Region，读在多个 Region 有 Replica（通过 CDC/Redshift 复制）。\n\n扩展延伸：DNS 流量调度：使用 AWS Route 53 / GCP Cloud DNS 的 Geo Routing 或 Latency-based Routing。数据同步：1）同步方式—— MySQL Binlog Replication / Kafka Cluster Linking / MongoDB Replica Set 跨 Region 节点 2）延迟——跨区域同步通常有 100ms-500ms 延迟，设计上需容忍最终一致性。故障切换流程：1）监测——Health Check 每隔几秒探测各 Region 的 API 健康状态 2）切换——DNS TTL 设短（30-60s）或直接用流量调度的 API 切换 3）回切——主 Region 恢复后持续观察，确认正常后切回。一致性权衡：多 Region 部署中强一致性 = 高延迟（因为需要跨 Region 协商），通常选择最终一致性。Google Spanner 用 TrueTime API 实现跨 Region 强一致性，但成本极高。实际方案：核心业务（支付/订单）用 Active-Passive（保证强一致），非核心业务（评论/通知）用 Active-Active（用户就近读写，容忍异步同步）。","hints":["多活架构最大的技术挑战是什么","DNS 切换为什么会有延迟"],"tags":["多区域","容灾","高可用"],"id":5042},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"缓存与数据库一致性方案","content":"请解释缓存（Redis）和数据库（MySQL）之间的数据一致性问题及主流解决方案。","answer":"答案：缓存和数据库的一致性问题源于两者的原子操作无法保证——读取时可能拿到缓存旧数据或数据库未提交的数据\n\n解析：更新缓存的常见模式：1）Cache-Aside（旁路缓存）— 读取：先读缓存，miss 则读 DB 并写缓存。更新：先更新 DB，再删除缓存（或更新缓存）。写多读少的场景删除缓存比更新缓存好（淘汰比更新简单，避免竞争条件）。2）Read-Through / Write-Through — 缓存层代理 DB 操作。3）Write-Behind — 异步写回 DB（高吞吐但有丢失风险）。Cache-Aside 的问题：并发写时先更新 DB 再删缓存，如果删缓存失败，旧数据留在缓存中。解决：延迟双删（先删缓存 -> 更新 DB -> 延迟 N 毫秒再删一次缓存），或使用 Change Data Capture（监听 Binlog 变更后异步删缓存）。\n\n扩展延伸：Cache-Aside 中「先更新 DB 再删缓存」和「先删缓存再更新 DB」哪个更好？主流推荐「先更新 DB 再删缓存」——因为先删缓存再更新 DB 可能导致并发读时缓存被其他线程写回旧数据（A 删缓存 -> B 读 DB（旧数据）写缓存 -> A 更新 DB）。使用 RabbitMQ 或 Redis Stream 做可靠删除——删缓存失败的消息入队列，异步重试。也可以使用 Read/Write Lock——读操作读取时加读锁防止写并发。业务容忍度：大多数场景缓存短时间不一致是可接受的（最终一致性），只有强一致场景（如库存、余额）才需要特殊处理。Facebook 的论文《Scaling Memcache at Facebook》描述了 Cache-Aside + 异步删除的实践——通过 MCRouter 做缓存代理 + 后台 Daemon 监听 DB 更新异步删缓存。Garnet（微软开源的缓存系统）支持更强的一致性模型。","hints":["先更新 DB 再删缓存和先删缓存再更新 DB 各自的并发问题","延迟双删中延迟时间怎么确定"],"tags":["缓存","一致性","数据库"],"id":5043},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"数据库读写分离与主从延迟","content":"数据库读写分离架构中如何处理主从延迟导致的读写不一致问题？","answer":"答案：主从延迟导致写后读不一致——用户写入主库后立即读取从库可能读到旧数据\n\n解决方案：1）读写分离强制读主——对一致性要求高的查询（如支付完成后查看订单状态）强制路由到主库，使用「读主库」标记或 Hint。2）数据版本号——写入时在 Redis 记录「用户 X 的最后写入时间」，读从库时检查该时间与从库的 Seconds_Behind_Master，如果延迟超过阈值则读主库。3）数据库中间件（ShardingSphere / MyCat）— 实现写后读一致性（Write-Read Separation），写入后 N 毫秒内的同一用户请求路由到主库。4）业务层面容忍——对于不关键的查询（如商品详情页的评论数），允许短暂不一致（因为评论数从 99 变成 101 用户看不出来）。\n\n扩展延伸：主从延迟的常见原因：1）从库硬件性能不如主库 2）从库执行大事务（批量更新）导致延迟 3）从库在做备份或 Analyzing 表 4）从库的 CPU/IO 被其他查询占用。延迟监控：在从库执行 SHOW SLAVE STATUS 监控 Seconds_Behind_Master。如果持续超过阈值（如 30 秒）发出告警。半同步复制（Semi-Sync Replication）：主库等待至少一个从库确认收到 Binlog 后才提交事务，保证数据至少在一个从库上可用。MySQL Group Replication 或 InnoDB Cluster 提供更强的一致性保证。读写分离的架构演进：应用层实现（多数据源配置）-> 数据库中间件（如 ProxySQL）-> 云服务（RDS 的读写分离自动路由）。缓存 + 读写分离组合：用户写入主库后同时更新 Redis 缓存，读从库 + 读缓存补偿——用户查询走 Redis 缓存（读写后缓存强一致），如果缓存 miss 再查询从库。","hints":["从库 Seconds_Behind_Master 是怎么计算的","半同步复制相比异步复制在性能上有什么牺牲"],"tags":["读写分离","主从","延迟"],"id":5044},{"category":"system_design_extras","difficulty":"medium","type":"choice","title":"技术设计评审要点","content":"以下哪项不是技术设计评审（Design Review）时应重点关注的维度？","options":["A) 方案是否满足功能需求","B) 方案的可扩展性和演进路径","C) 代码的命名规范和行数","D) 方案的安全性和异常处理"],"answer":"C","hints":["Design Review 关注架构级问题（可扩展性、安全性、可靠性），代码风格和命名规范是 Code Review 的关注点"],"tags":["设计评审","Architecture","Review"],"id":5045},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"API 限流策略设计","content":"请设计一套 API 限流方案，支持多维度限流（用户/IP/接口）并提供友好拒绝体验。","answer":"答案：API 限流需要多维度限流规则 + 滑动窗口算法 + 友好的限流响应\n\n解析：限流维度：1）用户级别——每个用户每秒/每分钟的 API 请求配额（如 100 QPS per user）2）IP 级别——防止单个 IP 恶意攻击（如 1000 QPS per IP）3）接口级别——不同接口不同配额（如写接口比读接口限流更严格）4）全局级别——保护整个系统的最大吞吐。算法选择：滑动窗口（Sliding Window Log 或 Sliding Window Counter）比固定窗口（每分钟重置计数器）更平滑，防抖动。Token Bucket 适合允许突发流量的场景。实现方式：1）Redis + Lua 脚本保证原子性（INCR + EXPIRE）2）分布式限流需要 Redis Cluster 或 Sentinel 3）SENTINEL 模式下的限流推荐本地 Token Bucket（减少网络开销）+ Redis 做全局协调。\n\n扩展延伸：友好的限流响应：HTTP 429 Too Many Requests + Retry-After Header 告知客户端何时重试。限流信息的传递：通过 X-RateLimit-Limit / X-RateLimit-Remaining / X-RateLimit-Reset Headers（GitHub API 风格）。分级限流策略：1）L1—Nginx 层（IP 限流）2）L2—API Gateway（用户 + 接口限流）3）L3—业务层（根据业务复杂度的动态限流）。分布式限流的挑战：Redis 单点瓶颈（每个请求都查 Redis）。优化策略：本地预分配 + 周期性同步（Token Bucket 定时从 Redis 获取配额配额到本地）。降级响应：限流后返回友好提示（「系统繁忙，请稍后再试」）+ 缓存的历史数据（如有）。限流的动态调整：根据系统负载（CPU/内存/延迟）自动调整配额。Sentinel / Resilience4j 在应用层实现限流和熔断。","hints":["滑动窗口相比固定窗口限流有什么优势","分布式限流中每次请求都查 Redis 的性能问题怎么解决"],"tags":["限流","API","设计"],"id":5046},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"蓝绿部署与金丝雀发布的容量规划策略","content":"蓝绿部署和金丝雀发布是实现零宕机发布的关键技术。请阐述两种模式的容量需求差异：\n1. 蓝绿部署需要多少冗余容量才能在不降级的情况下完成切换？\n2. 金丝雀发布的流量比例如何动态调整，以及在不同阶段需要预留多少冗余资源？\n3. 在云原生环境下，如何利用 Auto Scaling 动态管理部署所需的额外容量？","answer":"答案：\n蓝绿和金丝雀的容量需求本质不同——蓝绿需要 2 倍容量，金丝雀需要增量且可动态调整的容量。\n\n解析：\n**1. 蓝绿部署容量规划**：\n- 基础要求：同时运行两套全量环境（Blue + Green），各承载 100% 流量能力。总共需要 2 倍正常容量。\n- 优化方案：如果允许短暂的「降级窗口」，可在切换窗口期间只启动 70% 的新环境，借助滚动式扩容补满。\n- 数据库问题：Blue-Green 的数据库兼容性是最棘手的问题——需要反向兼容的 Schema 变更（Backward-Compatible Migrations）。\n\n**2. 金丝雀发布容量规划**：\n- 初始阶段（1-5% 流量）：只需原集群的少量额外实例。\n- 渐进阶段（10-50%）：需要逐步扩容新版本集群。\n- 全量阶段（100%）：旧版本逐步缩容，回收资源。\n- 关键点：在金丝雀的每个阶段都要保留「快速回滚」的容量（即旧版本实例不可立刻销毁）。\n- 一个实用模型：金丝雀阶段保留 1.5x 的峰值容量（0.5x 给新版本，1x 给旧版本），便于快速回滚。\n\n**3. Auto Scaling 策略**：\n- 使用 HPA（Horizontal Pod Autoscaler）监控新版本集群的 CPU/内存/Latency，动态调整副本数。\n- 配合 PDB（Pod Disruption Budget）确保任何时候有足够可用实例。\n- 预热（Warm-up）：新实例上线后先承载少量流量再逐渐增加，避免因 JVM 冷启动、缓存未预热导致 Latency 飙高。\n- 容量规划自动化：通过「部署预算」（Deployment Budget）声明式管理——「发布期间最多额外消耗 30% 的集群总容量」。\n\n扩展延伸：\n- 蓝绿的金丝雀化：大型系统常做「蓝绿 + 金丝雀」混合——每个环境内部再做金丝雀流量分割。例如，先切 1% 到新 Green 环境，验证后再全切。\n- 基础设施成本：蓝绿的 2 倍成本在很多情况下不划算——所以大多数互联网公司选择金丝雀而不是纯粹的蓝绿。\n- 流量镜像（Traffic Mirroring / Shadowing）也是容量评估的手段——复制真实流量到新版本但不影响线上用户，用于验证性能和正确性。","hints":["蓝绿需要两套全量环境，金丝雀只需要增量——这是核心容量差异","回滚能力也是一种「容量需求」——需要保留旧版本实例"],"tags":["蓝绿部署","金丝雀发布","容量规划","部署策略"],"id":5047},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"监控告警体系设计：从指标采集到告警降噪","content":"监控告警体系是保障系统稳定性的基石，但告警风暴（Alert Storm）和无效告警（Noise）是普遍痛点。请设计一套完整的监控告警体系，涵盖：\n1. 指标采集的多层架构（基础设施层、应用层、业务层）；\n2. 告警规则的分级管理策略；\n3. 告警降噪的常用技术（聚合、抑制、静默、去重）；\n4. 基于 SLO 的告警设计方法。","answer":"答案：\n成熟的监控告警体系应当从「多指标采集」到「有意义的告警」，每一层聚焦不同的关注点。\n\n解析：\n**1. 指标采集多层架构**：\n- 基础设施层：CPU/Mem/Disk/Network（Node Exporter + Prometheus）。\n- 容器/平台层：容器状态、Pod 资源使用、集群事件。\n- 应用层：延迟（Latency）、流量（Traffic）、错误（Errors）、饱和度（Saturation）——Google 的四大黄金信号。\n- 业务层：订单量、转化率、支付成功率——直接影响用户体验和营收。\n\n**2. 告警分级管理**：\n- P0（Critical）：核心业务中断、用户无法完成交易 -> 立即响应（5 分钟内）。\n- P1（Major）：主要功能受限、大量用户受影响 -> 30 分钟响应。\n- P2（Warning）：功能缓慢、少量用户受影响 -> 工作时间处理。\n- P3（Info）：不影响用户但需要关注。\n- 关键原则：P0+P1 的告警数量越少越好——如果每天收到 100+ P0，说明分级太宽松。\n\n**3. 告警降噪技术**：\n- 聚合（Aggregation）：同样的错误模式合并为一条告警，附上数量。\n- 抑制（Inhibition）：如果某个高优先级告警已触发，自动压制相关的低优先级告警（如「主机宕机」压制「主机上所有服务告警」）。\n- 静默（Silencing）：已知的维护窗口/已知问题手动静默。\n- 去重（Deduplication）：相同告警在短时间内多次触发只发一次。\n- 告警规则设计的黄金法则：确定性原则——告警的修复动作必须是可执行的，不能只是「看着有问题」。\n\n**4. SLO 驱动设计**：\n- 定义 SLO（Service Level Objective），围绕 Error Budget（错误预算）设计告警。\n- 告警触发条件不是「超过阈值」，而是「错误预算消耗速度超过预期」。\n- 示例：30 天内错误预算消耗 > 50% * SLO -> Warning；> 80% -> Critical。\n\n扩展延伸：\n- ON-CALL 文化的核心：告警要 actionable（可操作），不要发「噪音」。\n- 推荐阅读 Google SRE 书中的「Monitoring Distributed Systems」章节——特别是「四个黄金信号」和「抗告警疲劳」的讨论。\n- 工具生态：Prometheus + AlertManager + Grafana 是开源标准（「Prometheus Stack」）。\n- 实施建议：先做 SLO 再设置告警规则——没有 SLO 的告警就是没有根的告警。","hints":["好的告警体系应该让值班的人「没事可做」——而不是被告警淹没","告警降噪的核心是「抑制」和「分级」——不是不告警，而是只在需要行动时告警"],"tags":["监控告警","指标采集","告警降噪","可观测性","SRE"],"id":5048},{"category":"system_design_extras","difficulty":"medium","type":"short_answer","title":"分布式 ID 生成器：雪花算法变种与优化","content":"雪花算法（Snowflake）是分布式 ID 生成器的经典方案。请阐述其核心结构（时间戳+机器ID+序列号），分析其在实际应用中面临的问题（如时钟回拨、机器ID上限），并介绍至少两种改进变种方案（如百度的 UIDGenerator、美团的 Leaf）及其优化思路。","answer":"答案：\n雪花算法通过「时间戳 + 机器 ID + 序列号」生成 64 位唯一 ID，但时钟回拨和机器 ID 管理是其经典痛点。\n\n解析：\n**雪花算法核心结构**（通常位分配）：\n- 1 bit：符号位（0）。\n- 41 bits：毫秒时间戳（约 69 年）。\n- 10 bits：机器 ID（1024 台）。\n- 12 bits：序列号（每毫秒 4096 个）。\n\n**主要问题**：\n1. **时钟回拨**（Clock Drift / Backwards）：NTP 同步导致时间倒退 -> 可能产生重复 ID。\n2. **机器 ID 上限**：1024 台不够用。\n3. **序列号溢出**：同一毫秒内超 4096 个请求时等待下一毫秒。\n4. **长期趋势**：时间戳占位固定，如果 69 年后系统还在运行需整体迁移。\n\n**变种方案**：\n1. **百度 UIDGenerator**：\n   - 使用 RingBuffer 预生成 ID + CAS 扣减，而非序列号自增。\n   - 通过「外部化 WorkerID 分配」（ZooKeeper 管理）解决机器 ID 上限。\n   - 可自定义位分配（如扩大机器 ID 位数）。\n2. **美团 Leaf**：\n   - Leaf-segment：使用数据库步长（step）批量获取 ID 段，减少 DB 压力。\n   - Leaf-snowflake：仍使用雪花结构，但通过 ZooKeeper 动态注册 WorkerID 并持久化上次时间戳 -> 时钟回拨时比较 ZK 记录。\n3. **改进的时钟回拨方案**：\n   - 容忍策略：回拨 < 1s -> 等待追赶上。\n   - 内存标记策略：记录上次生成 ID 的时间戳，回拨时使用「预留序列号」或延迟生成。\n\n扩展延伸：\n- 为什么不直接用自增主键？分布式场景下自增主键在合并、迁移、跨库时产生冲突。\n- UUID 的局限性：不是递增的，不适合作为 MySQL InnoDB 主键（B+Tree 分裂）。\n- 趋势：新方案逐渐统一使用「分段发号 + 雪花混合」——既有趋势递增（利于索引）又有去中心化生成（利于扩展）。\n- 对于全球多活的极端场景，雪花的时间戳可用「逻辑时钟」（Logical Clock）替代物理时间戳，彻底解决时钟回拨。","hints":["时钟回拨是雪花算法最经典的问题——解决方案分「容忍」和「预防」两类","ID 生成器的核心要求：全局唯一 + 趋势递增 + 高可用"],"tags":["分布式ID","雪花算法","ID生成器","架构设计"],"id":5049},{"category":"system_design_extras","difficulty":"medium","type":"short_answer","title":"短 URL 系统的高性能重定向设计","content":"短 URL 服务（如 bit.ly、t.cn）需要支撑高 QPS 的重定向请求。请设计一个高性能短 URL 系统，重点阐述：\n1. 短码生成策略（Base62、预生成池）的选型与优化；\n2. 重定向链路上的性能优化（缓存策略、CDN 加速、HTTP 302/301 的选择）；\n3. 如何确保系统在高并发（10万+ QPS）下稳定运行，包括降级和容错方案。","answer":"答案：\n短 URL 系统的高性能核心在于「读多写少」——通过多级缓存和 CDN 边缘加速实现高吞吐重定向。\n\n解析：\n**1. 短码生成策略**：\n- Base62 编码（0-9a-zA-Z，62 进制）：对数据库自增 ID 编码，生成唯一短码。\n  - 优点：递增、唯一、可反向解析 ID。\n  - 缺点：自增 ID 存在顺序预测风险。\n- 预生成池（ID Segments）：预先从 DB 取一段 ID 范围缓存在本地，生成时从内存拿。\n  - 优点：减少 DB 写压力，支持高吞吐。\n  - 优化：可批量取号（如一次取 1000 个），消耗完再取。\n- 其他方案：随机短码 + 碰撞检查（性能较差），MD5 摘要截取（碰撞概率可控但非线性的）。\n\n**2. 重定向链路的性能优化**：\n- 缓存策略：Redis 集中缓存（短码 -> 长 URL 映射），设置 TTL（如 24h）。\n  - 热点短码（高频 URL）可使用本地缓存（Caffeine/LRU），减少 Redis 压力。\n- HTTP 状态码：\n  - **301（永久重定向）**：浏览器缓存结果，不再请求短 URL 服务。适合不可变的 URL。\n  - **302（临时重定向）**：每次都要请求短 URL 服务。适合可变的 URL（可更新目标）。\n  - 推荐：默认用 301（减少服务端压力），有编辑需求的 URL 用 302。\n- CDN 加速：短 URL 域名配置 CDN -> CDN 边缘缓存 301/302 响应，命中率可达 95%+。\n  - CDN 缓存 TTL 可设为 1-6 小时，配合主动 purge 更新。\n\n**3. 高可用保障**：\n- 读写分离：读流量（重定向）走缓存 -> DB；写流量（生成短码）直接走 DB。\n- 降级方案：缓存不可用 -> 降级为直连数据库（加限流保护）；DB 不可用 -> Read-Only 模式返回错误提示。\n- 限流：按 API Key/IP 限流写接口，读接口一般无需限流（缓存扛得住）。\n\n扩展延伸：\n- 安全问题：短 URL 可被用于钓鱼链接——建议加入「安全预览页」（缩短跳转前展示目标域名）或使用 Safe Browsing API 检测。\n- 数据价值：短 URL 系统记录的点击数据（Referrer、User-Agent、IP、时间）可用于流量分析。\n- 业界参考：bit.ly 每天处理数亿次重定向，核心架构就是「多级缓存 + 预生成短码 + 301 CDN 缓存」。","hints":["短 URL 系统是典型的「写少读多」场景——优化重心在重定向链路","用 301 还是 302 取决于是否需要更新目标 URL 的能力"],"tags":["短链接","URL缩短","重定向","高性能","缓存"],"id":5050},{"category":"system_design_extras","difficulty":"medium","type":"short_answer","title":"多租户 SaaS 系统的数据隔离方案","content":"多租户（Multi-Tenancy）是 SaaS 系统的核心架构模式。请阐述三种常见的数据隔离方案——独立数据库、共享数据库独立 Schema、共享数据库共享表——的架构设计、优缺点对比，并说明如何根据租户规模、安全需求、运营成本来选择合适的方案。另外讨论「混合模式」（Hybrid Tenancy）的适用场景。","answer":"答案：\n三种数据隔离方案形成了「安全/隔离性 vs 成本/运维复杂度」之间的三角权衡。\n\n解析：\n**三种方案对比**：\n| 维度 | 独立数据库 | 共享DB独立Schema | 共享DB共享表 |\n|------|-----------|-----------------|-------------|\n| 隔离性 | 最高 | 中等 | 最低（Row-Level） |\n| 安全性 | 物理隔离 | 逻辑隔离 | 应用层隔离 |\n| 运维成本 | 最高（N个DB） | 中 | 最低 |\n| 扩展性 | 自然隔离 | Schema多影响迁移 | 需要TenantID索引 |\n| 平均成本 | 高 | 中 | 低 |\n\n**选型指南**：\n- 独立数据库：大型租户（Enterprise）、强合规行业（金融、医疗）、需要独立备份恢复。\n- 共享DB独立Schema：中型租户、有一定隔离性需求但不想为每个租户建独立DB。\n- 共享表：小型租户（成千上万）、免费/低客单价产品。\n\n**混合模式**在实践中最为常见：\n- 大客户（Enterprise）-> 独立数据库。\n- 中小客户 -> 共享 DB 独立 Schema。\n- 免费/试用 -> 共享表。\n- 应用层通过路由配置决定每个租户使用哪种模式——框架如 Rails 的 Apartment Gem。\n\n**数据隔离的技术细节**：\n- 共享表方案必须使用「TenantID 列 + 复合索引」，所有 SQL 加 WHERE tenant_id 约束——漏掉就是数据泄露事故。\n- 安全性增强：Row-Level Security（如 PostgreSQL RL Policy）作为防御加固。\n- 共享 Schema 方案：每个 schema 独立，迁移时需要遍历所有 schema。\n\n扩展延伸：\n- Salesforce 是共享表方案的成功典范——通过精心的索引设计 + 强大的 Metadata 层支撑数百万租户。\n- 欧盟 GDPR 要求：某些场景下需要「Right to Erasure」（删除租户的所有数据）——独立数据库方案最简单（直接删库），共享表需要逐行清理。\n- 性能瓶颈在共享表方案中最明显：一个热点 Tenant 产生的数据影响其他租户的查询性能。解决方案是「Tenant 级资源隔离」（如 Pg 的 cgroup）。\n- 不推荐一开始就选择共享表——对初创 SaaS，建议从共享 Schema 开始，后期将大客户迁移到独立 DB。","hints":["隔离性、成本、运维复杂度三选二——没有完美方案","混合模式是工业界的常态：大客户独立 DB，小客户共享"],"tags":["多租户","SaaS","数据隔离","租户隔离","架构设计"],"id":5051},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"异地多活架构","content":"请解释异地多活架构的原理和设计挑战。对比「冷备」、「主备切换」和「多活」三种灾备模式，说明异地多活的难点和常见解决模式。","answer":"三种灾备模式对比：\\n\\n1. 冷备（Cold Standby）:\\n   - 数据备份到异地，故障后重新部署 + 恢复数据\\n   - RTO（恢复时间目标）：小时~天，RPO（恢复点目标）：天级\\n   - 成本最低，适合非关键系统\\n\\n2. 主备切换（Active-Passive / Warm Standby）:\\n   - 备机持续从主同步数据，主故障后手动/自动切换到备\\n   - RTO：分钟级，RPO：秒级（取决于同步延迟）\\n   - 备机平时不承担业务流量，资源利用率低\\n   - 常见问题：切换后可能丢最后几秒数据（异步复制）、切换过程有脑裂风险\\n\\n3. 异地多活（Active-Active / Multi-Site）:\\n   - 多个机房同时在线服务，任一机房故障流量切到其他机房\\n   - RTO < 30s，RPO = 0（接近零数据丢失）\\n   - 资源利用率高（所有机房都承担流量），但架构复杂度大幅上升\\n\\n异地多活的核心难点：\\n\\na) 数据冲突问题：同一用户可能在不同机房同时写数据\\n   - 解决：按用户 ID 分片（单元化），同一用户的所有写操作路由到固定单元\\n   - 跨单元数据访问走异步同步（最终一致性）\\n\\nb) 数据同步延迟：跨机房网络延迟 RTT 通常 10-50ms（同城）或 50-200ms（异地）\\n   - 解决：写本地 + 异步复制；关键数据用 Paxos/Raft 共识协议实现强一致\\n\\nc) 流量调度：如何将用户流量正确路由到就近/指定的机房\\n   - 解决：GSLB（全局负载均衡）+ DNS + 应用层路由（根据 user_id 或地域）\\n\\nd) 故障切换影响范围：切流量时已有连接、会话状态如何处理\\n   - 解决：Session 无状态化（Token + Redis 全局 Session）+ 连接平滑迁移\\n\\n常见模式：\\n- 同城双活（Metro Active-Active）：10km 内，延迟低，不解决地域级灾害\\n- 异地多活（Geo Active-Active）：真正解决地域级灾难（地震/洪水），但延迟和复杂度最高","hints":["异地多活中如何解决数据写入冲突——两个机房同时修改同一数据怎么办？","单元化架构（Unit Architecture）如何解决异地多活的数据一致性问题？"],"tags":["高可用","异地多活","灾备"],"id":5052},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"单元化架构设计","content":"请解释单元化架构（Unit Architecture / Cell-based Architecture）的核心原理。如何划分单元、处理跨单元请求、以及单元故障时的流量调度策略。","answer":"单元化架构核心原理：将系统划分为若干个「独立运行单元」（Cell/Unit），每个单元包含完整的技术栈（计算 + 存储），服务一部分用户，单元之间尽可能解耦。\\n\\n单元划分策略：\\n1. 按用户 ID 哈希分片（最常用）：user_id % N → 确定所属单元\\n2. 按地域/数据中心：华东用户进华东单元，华南用户进华南单元（降低延迟）\\n3. 按租户（SaaS 场景）：大租户独占单元，小租户共享单元\\n4. 按数据属性：如用户维度在 A 单元、订单维度在 B 单元（需要跨单元查询）\\n\\n跨单元请求处理：\\n- 最佳实践：尽量让同用户的请求落在同一单元（避免跨单元调用）\\n- 无法避免时（如用户 A 的订单需要用户 B 的数据），通过异步消息或全局服务（Global Service Layer）协调\\n- 高频跨单元调用 → 说明单元划分不合理，需要调整分片策略\\n\\n单元故障时的流量调度：\\n- 健康检查 + 故障检测 → 标记单元为不健康\\n- DNS / GSLB 将故障单元的流量切到健康单元\\n- 数据层处理：\\n  - 滑动分片：故障单元的数据由相邻单元接管（需要数据同步机制）\\n  - 冗余副本：每个单元的数据在另一个单元有只读副本\\n  - 降级策略：跨单元操作降级为「读本地 + 写本地 + 延迟同步」\\n- 恢复后做数据回填：故障单元重新上线后，从备份恢复增量数据\\n\\n优点：\\n- 故障隔离：一个单元故障不影响其他单元\\n- 弹性扩容：线性扩展——加单元即可加容量\\n- 多活基础：天然支持异地部署\\n\\n缺点：\\n- 跨单元查询成本高\\n- 运维复杂度上升（多套部署环境）\\n- 全局性功能（如全局排重）需要专门设计","hints":["单元化架构中什么情况下会产生「跨单元请求」？如何尽量减少？","一个单元完全故障后，其他单元如何接管其数据和流量？"],"tags":["单元化架构","高可用","扩展性"],"id":5053},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"数据库水平扩容","content":"请说明数据库水平扩容（Horizontal Scaling）的常见方案和挑战。包括分库分表策略、数据迁移方案（停机迁移 vs 在线迁移）、以及分布式 ID 生成。","answer":"水平扩容方案：\\n\\n分片策略：\\n1. 范围分片（Range）：按 ID 范围划分（1-1M→Shard1, 1M-2M→Shard2）\\n   - 优点：范围查询友好、扩容时只需加新范围\\n   - 缺点：数据倾斜（热点数据集中在一个范围）\\n2. 哈希分片（Hash）：user_id % N\\n   - 优点：数据分布均匀\\n   - 缺点：扩容时大量数据需要迁移（rehashing）\\n3. 一致性哈希（Consistent Hash）：引入虚拟节点，减少扩容时的迁移数据量\\n   - 优点：扩容只影响相邻节点，迁移数据最少\\n\\n数据迁移方案：\\n\\na) 停机迁移：\\n   - 停服 → 导出数据 → 按新分片规则导入 → 切 DNS → 恢复服务\\n   - 简单可靠，但需要停服窗口（适用于可容忍停机场景）\\n\\nb) 在线迁移（双写方案）：\\n   - 步骤 1：旧库 + 新库同时写入（应用层双写）\\n   - 步骤 2：用旧数据做全量迁移\\n   - 步骤 3：增量追平（校验新库和旧库的数据一致性）\\n   - 步骤 4：切读流量到新库\\n   - 步骤 5：切写流量到新库 → 停止旧库双写\\n   - 关键：双写期间要保证幂等性，防止重复数据\\n\\n分布式 ID 生成：\\n- Snowflake 算法：时间戳（41bit）+ 机器 ID（10bit）+ 序列号（12bit）= 64bit\\n- 优点：全局唯一、趋势递增、无中心化依赖\\n- 变体：百度的 UidGenerator、美团的 Leaf（支持号段模式和 Snowflake 模式）\\n\\n扩容后的常见问题：\\n- 跨分片查询：分页/排序/聚合需要 Merge 层做结果合并\\n- 分布式事务：跨分片的修改需要用 TCC / Saga 补偿（2PC 不推荐）\\n- 数据倾斜：部分分片数据量远超其他分片 → 需要 rebalance 或拆分热点分片","hints":["哈希分片扩容时为什么会导致大量数据迁移？一致性哈希如何缓解？","在线迁移方案中「双写」阶段的核心风险是什么？"],"tags":["数据库","水平扩容","一致性哈希"],"id":5054},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"缓存一致性更新策略","content":"请对比常见的缓存一致性更新策略：Cache-Aside、Read/Write-Through、Write-Behind。分析各自的适用场景和一致性问题。包括先更新数据库还是先更新缓存的经典讨论。","answer":"常见缓存策略对比：\\n\\n1. Cache-Aside（旁路缓存）:\\n   - 读：先查缓存 → 未命中则查 DB → 回写缓存\\n   - 写：先更新 DB → 删除缓存（或更新缓存）\\n   - 最常用，实现简单，适合读多写少场景\\n   - 问题：「先删缓存再写 DB」和「先写 DB 再删缓存」哪个对？\\n     - 先删缓存再写 DB：并发读时缓存为空→读旧数据写缓存→导致脏数据（缓存与 DB 不一致）\\n     - 先写 DB 再删缓存：更安全（脏数据窗口更短），但删除可能失败→最终不一致\\n   - 推荐：「先写 DB 再删缓存」+ 延迟双删（写 DB→删缓存→延迟 N 毫秒→再删一次）\\n\\n2. Read/Write-Through（读写穿透）:\\n   - 缓存层作为数据源代理，应用只跟缓存交互\\n   - 读/写都由缓存委托给 DB，对应用透明\\n   - 适合：缓存即存储（Cache as a Service）的场景\\n   - 优点：应用逻辑简化，缓存与 DB 一致性由缓存层保证\\n   - 缺点：需要缓存中间件支持（如 Redis + 自定义代理），延迟略高\\n\\n3. Write-Behind（写回）:\\n   - 写操作只写缓存，由后台异步批量刷到 DB\\n   - 适合：写操作需要合并/削峰（如浏览计数、点击日志）\\n   - 优点：高吞吐写、可批量操作减少 DB 压力\\n   - 问题：缓存宕机时未持久化的数据丢失 → 需要持久化缓存 + 刷盘确认机制\\n\\n经典讨论——先更新 DB 还是先更新缓存：\\n- 先更新缓存再更新 DB：缓存成功 + DB 失败 → 数据永久不一致（不可接受）\\n- 先更新 DB 再更新缓存：DB 成功 + 缓存更新失败 → 下次读会加载旧数据，但最终可修复\\n- 结论：绝大多数场景「先更新 DB」更安全，配合「删除缓存而非更新缓存」效果更好\\n- 删除缓存优于更新缓存是因为：删除是幂等的，更新涉及并发写覆盖问题","hints":["为什么「删除缓存」比「更新缓存」更安全？并发场景下有什么不同？","Write-Behind 策略的最大风险是什么？适合什么场景？"],"tags":["缓存","一致性","性能优化"],"id":5055},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","content":"请说明全链路压测的设计要点。包括压测数据隔离（Mock / Shadow 表 / 逻辑隔离）、流量模型设计（比例分配、流量录制回放）、以及压测对生产环境的保护措施。","title":"全链路压测设计","answer":"全链路压测设计要点：\\n\\n1. 压测数据隔离——核心问题：压测数据不能污染真实业务数据。\\n   - Mock 模式：调用下游时用 Mock 服务返回模拟数据，适合单服务压测\\n   - Shadow 表模式：压测写入 Shadow 表（与真实表同结构，前缀区分），读时优先读 Shadow\\n   - 逻辑隔离：所有 SQL 请求携带压测标记（如 user_id 为负数 = 测试用户），拦截器自动路由到影子表/逻辑隔离区\\n   - 日志隔离：压测产生的业务日志、报警通知、消息队列消息需过滤掉\\n\\n2. 流量模型设计：\\n   - 比例分配：按真实业务流量比例分配请求（如读:写 = 8:2）\\n   - 流量录制回放（Replay）：从生产环境录制真实请求，去敏后回放（常用工具：GoReplay / TCPCopy）\\n   - 流量递增模型：匀速 → 阶梯递增 → 突发脉冲 → 持续高压，不同模型暴露不同问题\\n   - 考虑因素：新用户 vs 老用户比例、移动端 vs Web 端比例、高峰期 vs 低峰期流量特征\\n\\n3. 生产环境保护措施：\\n   - 熔断阈值：压测流量触达 CPU 80% / 内存 70% / 延迟 2x 基线时自动熔断\\n   - 数据清理：压测结束后自动清理影子数据，设超时自动恢复\\n   - 范围控制：压测只覆盖特定接口/特定模块，不扫描全站\\n   - 监控对齐：压测期间所有指标（RT、QPS、错误率、GC）实时对齐到同一个监控大盘\\n   - 压测标记透传：压测请求的标记需通过 HTTP Header / RPC Attachment 透传到所有下游服务，确保全链路降级/隔离生效\\n\\n4. 结果分析：\\n   - 瓶颈定位：CPU → 计算密集，IO → 数据库/网络，GC → 内存分配和对象创建\\n   - 拐点分析：哪个并发量下吞吐量开始下降、延迟开始陡增（系统容量拐点）\\n   - 容量规划：根据压测结果 + 业务增长预期，推算需要预留多少冗余","hints":["全链路压测最大的风险是什么？如何防止压测数据进入真实业务表？","压测流量如何透传到所有下游服务？为什么必须透传？"],"tags":["压测","全链路","容量规划"],"id":5056},{"category":"system_design_extras","difficulty":"medium","type":"short_answer","title":"变更数据捕获（CDC）管道设计","content":"请说明变更数据捕获（Change Data Capture, CDC）的核心原理和架构设计。对比基于日志解析（如 Debezium/Canal）和基于轮询（如 Polling）两种 CDC 方案的区别。CDC 管道在「全量初始化 + 增量同步」场景下如何保证数据一致性和不丢不重？","answer":"答案：\nCDC 通过捕获数据源的变更事件（插入/更新/删除），实时或准实时地将变更同步到下游系统，是构建实时数据管道和数据中台的核心技术。\n\n解析：\n**两种方案对比**：\n| 维度 | 日志解析（Log-Based） | 轮询（Polling-Based） |\n| 原理 | 解析数据库事务日志（Binlog / WAL / Redo Log） | 定期查询业务表（SELECT WHERE update_time > ?） |\n| 延迟 | 毫秒级（实时） | 秒-分级（取决于轮询间隔） |\n| 入侵性 | 无（读日志，不碰业务表） | 高（需要业务表有 update_time 字段） |\n| 删除捕获 | 天然支持 | 需要逻辑删除或墓碑表 |\n| 一致性 | 事务级一致（同一事务的变更原子性捕获） | 可能读到事务中间状态 |\n| 典型工具 | Debezium（MySQL/PostgreSQL/MongoDB）、Canal（阿里开源）、Maxwell | 自定义轮询任务 |\n\n**全量初始化 + 增量同步的流程**（以 Debezium 为例）：\n1. 全量快照：Connector 启动时先做 SELECT * 全量扫描，记录快照时的 Binlog 位置（GTID / LSN）。\n2. 增量接续：全量完成后，从记录的 Binlog 位置开始消费增量事件。\n3. 一致性保证：快照过程中产生的增量变更不会丢失（在快照前记录 Binlog 位置，快照后再从这个位置消费增量）。\n4. 至少一次语义（At-Least-Once）：Debezium 每条变更记录有唯一 offset（Binlog 文件名 + 位置），写入 Kafka 后记录 offset。Consumer 重启时从上次记录的 offset 恢复。\n5. 幂等消费：下游消费端做幂等处理（如 Upsert），保证即使偶发重复也不会产生数据不一致。\n\n**关键设计考量**：\n- Schema 变更传播：源表加列后，CDC Connector 需要能动态更新 Schema 并同步到下游（Debezium 通过 History Topic 记录 Schema 变更）。\n- 数据过滤：支持按库/表/列级别过滤（减少不必要的数据流量）。\n- 数据转换：在管道中嵌入 SMT（Single Message Transform）或使用 Kafka Streams 做轻量转换。\n- 故障恢复：Connector 故障重启后，从上次提交的 offset 继续消费（可能出现少量重复，但不丢数据）。","hints":["CDC 的核心不是数据同步技术，而是「事务日志的顺序回放」——这保证了一致性","为什么基于日志解析的方案能做到事务级一致性而轮询做不到——日志记录的是事务提交后的最终状态"],"tags":["CDC","Debezium","Canal","数据同步","实时数据"],"id":5057},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"数据质量监控系统设计","content":"请设计一个数据质量监控系统，能够对数据仓库/数据湖中的海量数据进行自动化质量检测。包括：\n1. 质量维度定义（完整性、准确性、一致性、及时性等）；\n2. 质量规则引擎架构（规则定义、调度执行、结果评估）；\n3. 异常检测与告警（静态阈值 vs 动态基线）；\n4. 数据质量分数模型（如何综合评价一个数据集的质量）。","answer":"答案：\n数据质量监控系统通过定义可量化的质量规则，自动化地对数据资产进行持续检测和评估，确保数据可信可用。\n\n解析：\n**1. 质量维度**：\n- 完整性（Completeness）：非空比例、必填字段缺失率。\n- 准确性（Accuracy）：值与真实世界的符合程度（如用户年龄不能超过 150）。\n- 一致性（Consistency）：跨系统同一数据值是否一致（如 A 系统的订单金额 = B 系统的支付金额）。\n- 及时性（Timeliness）：数据从产生到可用的延迟（SLA：T+1 早上 8 点前需可用）。\n- 唯一性（Uniqueness）：主键无重复、业务唯一键无冲突。\n- 有效性（Validity）：数据格式/取值范围符合业务规则（如邮箱格式、枚举值范围）。\n\n**2. 规则引擎架构**：\n- 规则定义 DSL：YAML/JSON 定义质量规则，例如：\n  name: order_amount_not_null\n    type: completeness\n    target: dwd.orders.pay_amount\n    condition: is not null\n    threshold: 0.99  # 非空比例 > 99%\n    schedule: daily_8am\n- 规则存储：Git（规则即代码）+ 数据库（运行实例和结果）。\n- 执行引擎：Spark 批处理（日/小时级别的大规模扫描）+ Flink 流处理（实时检测）。\n  - 设计原则：规则执行不扫描全表——利用分区裁剪 + 抽样（大数据集可用 STRATIFY 采样）。\n- 结果评估：每次执行生成 Quality Report（统计值、通过/失败、偏差百分比）。\n\n**3. 异常检测**：\n- 静态阈值：人工配置上下限（如非空率 > 99%、金额 > 0）。\n- 动态基线：基于历史数据自动计算波动范围（均值 +/- 3sigma / 移动平均）。\n  - 适用场景：数据量波动大、没有绝对阈值（如日常 DAU 波动在 +/-5% 以内，但活动期间可能 +50%——动态基线会排除活动日期）。\n- 告警分级：P0（数据不可用——阻断下游任务）、P1（质量下降——需确认）、P2（轻微偏差——仅通知）。\n\n**4. 数据质量分数**：\n- 基础模型：每条规则的加权分值（通过得满分，未通过按偏差比例扣分）。\n- 权重设计：核心表（如订单表）权重 > 维度表 > 中间表。关键维度（完整性 + 准确性）权重 > 辅助维度。\n- 综合评分 = sum(规则评分 * 规则权重 * 表权重) / sum(权重)。\n- 展示：数据目录中每个表显示质量标签（优秀/良好/警告/不达标）和趋势图。\n\n扩展延伸：\n开源工具：Great Expectations（Python，规则即代码 + Data Docs）、Deequ（AWS 开源，基于 Spark）。建议将数据质量监控作为数据 Pipeline（如 Airflow DAG）的最后一步任务。","hints":["数据质量检测的最大挑战是「大规模全表扫描的成本」——必须利用分区裁剪、采样和增量检测","动态基线在异常检测中的核心价值是「自适应」——业务有正常波动时不会误报"],"tags":["数据质量","数据治理","监控","规则引擎"],"id":5058},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"审计日志与合规追踪系统","content":"请设计一个企业级的审计日志系统（Audit Trail），用于满足合规要求（如 SOX、GDPR、PCI-DSS）。需要覆盖：\n1. 审计事件的采集（数据分类——谁在什么时间对什么数据做了什么操作）；\n2. 日志的防篡改保证（Immutable Log + 完整性校验链）；\n3. 高效的查询与检索（万亿级审计事件的搜索）；\n4. 合规报告自动化（权限访问报告、数据变更报告）。","answer":"答案：\n审计日志系统的核心要求是「不可否认性」——日志一旦写入，事后不能否认或篡改。设计围绕「写不可逆、查可高效、存可长久」展开。\n\n解析：\n**1. 审计事件采集**：\n- 标准化事件模型（CloudEvents 格式扩展）：\n  event_id: uuid\n  timestamp: 2026-06-04T10:00:00Z\n  actor: user_id: u123, ip: 10.0.0.1, session_id: s456\n  action: UPDATE\n  resource: type: ORDER, id: ord789\n  detail: changed_fields: status: from: PENDING, to: PAID\n  result: SUCCESS\n- 采集点：API 网关拦截（统一入口）、数据库触发器 / CDC、应用层 SDK 埋点。\n- 性能考虑：采集对业务代码的侵入性要最小化——使用 AOP / 拦截器 + 异步发送（消息队列）。\n\n**2. 防篡改保证**：\n- 方式一：Write-Once Storage（只写一次存储，如 AWS S3 Object Lock / 华为 GaussDB 的 Append-Only 表）。\n- 方式二：哈希链（Hash Chain / Blockchain-light）：\n  - 每条日志记录包含前一条日志的 SHA256 哈希值。\n  - 定期生成 Merkle Tree Root，将 Root Hash 发布到公开可验证的渠道（如区块链 / 报纸 / 公共 DNS TXT 记录）。\n  - 验证时：给定任意日志条目，从该条目沿哈希链走到最近的 Merkle Root，计算路径哈希是否匹配。\n- 方式三：数字签名——每条日志落盘前用 HSM（硬件安全模块）签名。\n- 访问控制：审计日志本身只能追加（Append-Only），DELETE/UPDATE 在数据库层面禁止（通过 Trigger/RDS 权限/存储过程）。\n\n**3. 高效查询**：\n- 存储架构分层：\n  - 热存储（近 30 天）：Elasticsearch，按时间 + actor + resource_type 建索引。\n  - 温存储（30 天 - 1 年）：对象存储 + 列存格式（Parquet），通过 Presto/Trino 查询。\n  - 冷存储（> 1 年）：压缩归档到 Glacier / 冷存，需要时从归档恢复。\n- 分区策略：按日期分区 + 按 resource_type 二级分区。\n- 常用查询模式预优化：「用户 X 在时间范围内对 Y 资源做了什么」——建立 (actor_id, date) 复合索引。\n- 万亿级场景：使用时序数据库（如 TimescaleDB）或日志专用存储（如 Loki / Elasticsearch 冷热分离架构）。\n\n**4. 合规报告自动化**：\n- 预定义报告模板：权限访问报告（谁在什么时间访问了什么数据）、数据变更报告（敏感字段修改记录）、管理员操作报告。\n- 定时生成 + 邮件/消息推送。\n- 支持自定义报告：SQL + 图表（接入 BI 工具如 Grafana / Metabase）。\n- 法律保留（Legal Hold）：对涉及诉讼的数据，标记为保留状态——即使常规清理策略也不能删除。\n\n扩展延伸：\nGDPR 特别要求：审计日志本身包含个人数据（如 IP 地址），也需要符合 GDPR 的「数据最小化」和「保留期限」要求——日志中的个人信息需在保留期后自动匿名化。","hints":["哈希链（Hash Chain）为什么能防篡改——修改任意一条日志会导致其后所有日志的哈希不匹配","审计日志是「写优化」系统——写一次再也不改，所以写入吞吐是主要性能指标"],"tags":["审计日志","合规","安全","防篡改","数据治理"],"id":5059},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"云成本管理（FinOps）系统","content":"请设计一个云成本管理与优化系统（Cloud Cost Management / FinOps Platform）。需要覆盖：\n1. 多账号多云的成本数据采集与归一化（AWS/Azure/GCP/阿里云等）；\n2. 成本分摊模型（按标签/按项目/按业务线的分账能力）；\n3. 预算管理与异常告警（预测与实际对比、突发费用检测）；\n4. 成本优化建议引擎（识别闲置资源、RI/Spot 实例推荐、存储降配）。","answer":"答案：\n云成本管理系统的核心价值是「让每一分云支出都有归属、有控制、有优化空间」。企业上云后面临的最大挑战不是技术，而是成本失控——FinOps 是一套将财务责任下放到工程团队的运营框架。\n\n解析：\n**1. 成本数据采集与归一化**：\n- 数据源：AWS CUR（Cost and Usage Report）、Azure 成本管理 API、GCP BigQuery 导出、阿里云 BSS API。\n- 采集方案：定时任务（每日/每时）拉取各云厂商的账单文件。\n- 归一化：将不同厂商的计费项映射到统一模型（如 region、service、resource_id、usage_type、cost、tags）。\n- 存储：ClickHouse / StarRocks 做实时聚合分析（按时间、厂商、服务类型、标签等多维汇总）。\n- 资源元数据关联：将账单中的资源 ID 关联到 CMDB（配置管理数据库），获取资源的负责人、业务线等信息。\n\n**2. 成本分摊**：\n- 标签策略（Tagging Strategy）：规范资源标签（cost_center、project、environment、owner）。\n  - 未打标资源 = 无法分摊 = 成本黑洞 -> 强制标签策略（打标才能创建资源）。\n- 分摊模型：\n  - 直接分摊：通过标签直接归属到项目/部门。\n  - 按比例分摊：共享资源（如 RDS 共享实例、K8s 集群节点）按 CPU/Memory 使用比例分到各业务线。\n  - 固定比例分摊：基础设施费用按固定比例分配给所有业务线。\n- Showback 与 Chargeback：Showback（仅展示成本数据，不扣预算）-> Chargeback（实际扣减预算）。\n\n**3. 预算与告警**：\n- 预算设置：月度/季度/年度预算，分配到成本单元。\n- 实际 vs 预算对比：实时/每日对比（月度已使用预算百分比）。\n- 预测：基于过去 90 天的消费趋势预测月末总成本。\n- 告警阈值：50% -> 80% -> 100% -> 120% 阶梯告警。\n- 异常检测：机器学习检测意外费用峰值（如某一夜 EC2 费用翻倍——可能是新环境未打标、或被攻击）。\n\n**4. 优化建议引擎**：\n- 闲置资源检测：检测低利用率的资源（如 CPU < 5% 的 EC2、空负载的 Load Balancer、未绑定的 EBS 卷）。\n- 实例规格优化（Rightsizing）：基于过去 30 天的 CPU/Memory/Network 峰值，推荐更合适的实例规格。\n- RI/SP 推荐（预留实例/节省计划）：基于稳定的基础用量推荐购买 RI（1 年或 3 年）。\n- Spot 实例推荐：对可中断的工作负载（Flink 计算、Spark 任务、CI/CD）推荐使用 Spot（可节省 60-90%）。\n- 存储降配：EBS 冷数据卷推荐从 gp3 降级到 sc1、S3 超过 N 天未访问的对象自动过渡到 Infrequent Access / Glacier。\n- 节省金额量化：每条建议附带「预估月节省金额」和「实施难度」，帮助优先级排序。\n\n扩展延伸：\n开源工具：OpenCost（K8s 原生成本监控）、Cloud Custodian（策略引擎，自动停止闲置资源）。商业方案：Vantage、CloudHealth、Spot by NetApp。建议从「标签覆盖 + 成本可视化」起步，先让成本可见，再推动优化。","hints":["FinOps 的核心不是技术问题而是组织和流程问题——让工程师看到自己的成本，承担优化责任","成本分摊中最难解决的问题是「共享基础设施的分摊模型」——没有一个模型所有人都满意"],"tags":["FinOps","云成本","成本优化","Cloud Cost"],"id":5060},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"全局唯一 ID 生成器设计","content":"在分布式系统中设计一个全局唯一 ID 生成器，要求：全局唯一、趋势递增、高可用（99.999%）、低延迟（<5ms）。对比 Snowflake 算法和基于 Redis/数据库号段模式的方案。","answer":"Snowflake 方案：41bit 时间戳（毫秒级，可使用 69 年）+ 10bit 工作节点 ID（最多 1024 节点）+ 12bit 序列号（每毫秒 4096 个 ID）。优点：本地生成无需网络调用，延迟极低（微妙级），趋势递增。缺点：强依赖机器时钟，时钟回拨会导致 ID 冲突；节点数受限。\n\n号段模式：从数据库或 Redis 批量获取 ID 号段（如步长 1000），应用本地自增分配。优点：实现简单，无时钟问题，适合 MySQL 生态。缺点：依赖数据库/Redis 可用性；重启可能丢失未用完的号段。\n\n最佳实践：Leaf（美团）方案 = Snowflake（时钟回拨通过 1s 等待 + 未来时间补偿）+ 号段模式（双 Buffer 预加载，切换监控）。","hints":["Snowflake 时钟回拨问题的几种解决策略以及它们的 trade-off","号段模式中极端高并发下的号段用尽如何兜底"],"tags":["分布式ID","Snowflake","号段模式","高可用"],"id":5061},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"设计一个 Feature Flag / 灰度发布系统","content":"如何设计一个企业级的 Feature Flag（功能开关）系统？需要支持多层灰度（按用户 ID、地域、设备类型）、动态配置推送、A/B 测试和紧急降级。\n\n核心难点：1）配置实时推送的可靠性。2）灰度规则的表达与高效匹配。3）大规模下 SDK 的性能。","answer":"答案：Feature Flag 系统的核心架构分为三部分：管理平台（规则配置 + 发布管理）→ 配置分发（实时推送 + 存储）→ SDK（规则评估 + 本地缓存）。业界参考：LaunchDarkly、Flipper、Unleash。\n\n解析：1）规则模型——规则的本质是一个决策树/表达式引擎。核心数据结构：Flag（开关名）+ Target（匹配规则，如 user_id IN [1001,1002] OR region = 'US'） + Variation（返回的变量值，true/false 或 string 多值）。规则优先级排序越具体的规则越优先。表达式引擎选型：自研简单 DSL（JSON 格式的 OR/AND/NOT 组合）vs 嵌入表达式引擎（MVEL / Aviator / Lua）。2）配置分发——配置存数据库 + 缓存到 Redis。推送机制：WebSocket 长连接（即时推送）+ HTTP 定时轮询兜底（如 30s 拉一次）。配置变更写入数据库 → MQ 广播通知 → 各服务收到通知后拉取最新配置 → 本地缓存更新。3）SDK 设计——嵌入业务应用中，关键要求：毫秒级规则评估不阻塞业务逻辑。本地缓存全量 flag 配置 + 定期后台刷新。规则评估不抛异常（评估失败返回默认值 fallback）。采样日志记录哪些 flag 被评估了（用于分析活跃开关和排查）。\n\n扩展延伸：工程落地：1）灰度能力——按比例（5% 流量开新功能）、按属性（白名单用户先行）、按地域/时段。2）A/B 测试集成——Feature Flag + 实验平台：Flag 指定实验组，SDK 记录用户所属分组，实验结果自动分析。3）紧急降级——开关配置预定义降级策略：某个依赖服务故障时一键开启降级开关，所有流量走降级路径。4）开关生命周期管理——废弃的 flag 需要清理工具（静态代码扫描找出代码中不再使用的 flag 引用）。5）权限管理——谁可以创建/修改/发布 flag，灰度发布需要审批流程（先灰度 1% → 验证 → 10% → 50% → 全量）。6）与配置中心的区别——配置中心管静态配置（数据库地址、线程池大小），Feature Flag 管业务逻辑开关和灰度，两者可以合并（如 Nacos 同时支持配置和开关）但职责不同。","hints":["毫秒级规则评估不阻塞业务——本地缓存 + 后台异步刷新 + 评估失败返回默认值","废弃的 Feature Flag 怎么清理——静态代码扫描 + 运行时使用统计"],"tags":["系统设计","灰度发布","Feature Flag","A/B测试","配置管理"],"id":5062},{"category":"system_design_extras","difficulty":"medium","type":"choice","title":"分布式全局唯一 ID 生成场景选型","content":"某 IM 系统需要在离线消息表中生成全局唯一且趋势递增的消息 ID，用于客户端分页拉取和排序。用户量 5 亿，每天消息量约 50 亿条。以下哪种方案最合适？","options":["A) UUID v4（随机生成 128 位）","B) 数据库自增 ID（Auto Increment）","C) Snowflake 算法（64 位：时间戳 + 机器 ID + 序列号）","D) Redis INCR 生成连续递增 ID"],"answer":"答案：C) Snowflake 算法（64 位：时间戳 + 机器 ID + 序列号）\n\n解析：IM 消息 ID 的核心要求是全局唯一 + 趋势递增（按时间有序，方便分页 + 排序）+ 高性能。Snowflake 每秒单机可生成 409.6 万个 ID（12 位序列号），64 位长度适合做数据库主键，趋势递增满足分页排序需求。A 选项 UUID v4 128 位太长（增加索引存储开销），且无序（B-tree 索引频繁分裂，写入性能差），作为消息 ID 影响分页查询。B 选项数据库自增 ID 在 50 亿/天的规模下单库无法承载（约 5.8 万 QPS 写），分库后自增 ID 会重复或需要分段配置。D 选项 Redis INCR 性能高但带宽压力大（每次网络往返），Redis 集群模式下的 INCR 需要保证 key 在同一个 slot 才能原子递增，且 Redis 宕机可能跳号。\n\n扩展延伸：IM 消息 ID 的额外需求：1）客户端需要根据消息 ID 做增量拉取（拉取大于 last_message_id 的消息），Snowflake 的趋势递增天然支持。2）消息 ID 需要跨会话唯一还是仅会话内唯一？通常全局唯一 + 按会话分表。3）Snowflake 的时钟回拨问题——IM 场景可以接受「等待回拨间隔时间再生成」或「记录上次生成时间戳，回拨时用备用序列号空间」。4）Snowflake 变体：百度的 uid-generator 用 RingBuffer 预缓存 ID，美团的 Leaf 支持号段 + Snowflake 双模式切换。","hints":["趋势递增为什么比绝对递增更适合分布式消息 ID——客户端增量拉取和分页排序","Snowflake 的时钟回拨问题在 IM 场景怎么容错"],"tags":["分布式","ID生成","Snowflake","IM","选型"],"id":5063},{"category":"system_design_extras","difficulty":"hard","type":"fill_in_blank","title":"分布式系统的隔离级别与实现机制","content":"分布式数据库的隔离级别比单机数据库更复杂。快照隔离（Snapshot Isolation）通过___机制实现，每个事务看到的是___时刻的数据快照。可串行化（Serializable）隔离级别可以通过___协议（如 Google Spanner 使用）或___技术来实现。相比可重复读（Repeatable Read），快照隔离解决写偏序（Write Skew）需要额外的___检查。","answer":"{\"correct\":[[\"MVCC\",\"多版本并发控制\"],[\"事务开始\",\"事务启动\",\"start\"],[\"Paxos\",\"2PC\",\"两阶段提交\"],[\"TrueTime\",\"全局时钟\",\"时钟同步\"],[\"冲突检测\",\"写冲突检测\",\"可串行化\"]],\"distractors\":[\"锁机制\",\"提交\",\"Raft\",\"乐观锁\",\"死锁检测\"]}","hints":["MVCC 是多版本并发控制，每个事务启动时获取一个快照版本","Google Spanner 用 TrueTime + 2PC 实现外部一致性（可串行化）"],"tags":["分布式","事务隔离","MVCC","Spanner","一致性"],"id":5064},{"category":"system_design_extras","difficulty":"medium","type":"true_false","title":"缓存穿透、击穿与雪崩的区别","content":"缓存穿透（Cache Penetration）是指大量请求直接穿透缓存打到数据库，通常由缓存失效引起。缓存击穿（Cache Breakdown）是指某个热点 key 失效时高并发请求直接打到数据库。缓存雪崩（Cache Avalanche）是指在某一个时刻大量缓存同时失效导致请求全部打到数据库。判断以上描述是否正确。","options":["正确","错误"],"answer":"错误。解析：描述中「缓存穿透明确定义为缓存失效引起」这个说法不够精确。缓存穿透是指查询一个不存在的数据（缓存中也不存在，数据库中也不存在），每次请求都直接查数据库——解决方案是布隆过滤器预过滤或缓存空值（即使 DB 没有也缓存一个空结果）。缓存击穿的描述是正确的——热点 key 失效导致高并发直接查 DB，解决：热点 key 永不过期或者用互斥锁控制重建。缓存雪崩的描述基本正确——大量 key 同时失效（如设置了相同的 TTL）或缓存节点宕机，解决：TTL 加随机偏移、缓存集群高可用。\n\n扩展延伸：三者的根本区别——穿透是「数据本身不存在」导致防不胜防（解决方案在事前过滤），击穿是「单个热点 key 失效」导致（解决方案在封锁重建），雪崩是「大面积 key 同时失效」导致（解决方案在错峰失效 + 集群容灾）。实际生产中最危险的场景是穿透 + 击穿同时发生：某个热点 key 失效后，大量并发请求查 DB，而 DB 中该数据恰好不存在（比如被删除了），布隆过滤器也没更新，导致所有请求穿透到 DB——DB 直接被压垮。","hints":["缓存穿透的根因是数据不存在，不是缓存失效——布隆过滤器为什么能解决","缓存击穿 + 穿透同时发生是最危险的场景"],"tags":["系统设计","缓存","穿透","击穿","雪崩"],"id":5065},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"在线教育/直播场景的低延迟架构设计","content":"在线教育或直播场景下，如何保证音视频互动延迟低于 200ms？WebRTC、CDN、RTMP 等技术的选型？如何应对弱网环境？大规模万人直播课 vs 小班 1v1 互动在架构上的区别？","answer":"答案：低延迟的核心在于传输协议的选择和边缘网络的布局。延迟分级：CDN 分发（3-10s，适合点播）、RTMP/HLS（5-30s，适合传统直播）、WebRTC（< 500ms，适合互动）、SRT/QUIC（< 2s，适合弱网）。互动场景必须选择 WebRTC ± 自建媒体服务器。\n\n解析：1）WebRTC 的核心机制——P2P 直连（延迟最低，适合 1v1），需要信令服务器协调（SDP 交换 + ICE 候选地址收集）。多人场景需要 SFU（Selective Forwarding Unit，选择性转发）——每个客户端只上传一路视频到 SFU 服务器，SFU 根据需要转发给其他参与者。不推荐 MCU（Multipoint Control Unit）架构——服务器混流后再分发，CPU 消耗大且延迟高。2）万人课堂的架构——采用「一层分发 + 一层源站」：老师端推流到底层媒体服务器（单路），媒体服务器分发给边缘 CDN 节点（多路），学生端从最近的边缘节点拉流。互动环节（连麦）使用 WebRTC 回传。3）弱网优化——FEC（前向纠错，发送冗余包，丢包后可恢复）、NACK（丢包重传，增加延迟但节省带宽）、SVC 编码（分层编码，弱网时丢弃增强层只传基础层保证流畅）、JitterBuffer（抖动缓冲，以增加少量延迟换取平滑播放）。\n\n扩展延伸：选型建议：1）小班课（< 10 人）→ WebRTC + SFU（Mediasoup / Janus / LiveKit）部署边缘节点就近接入。2）大班课（千人+）→ WebRTC + CDN 混合：老师推流到媒体服务器转 RTMP/HLS 分发到 CDN，学生 CDN 拉流。连麦回传用 WebRTC。3）1v1 互动 → WebRTC P2P 直连，TURN 服务兜底（NAT 穿透失败时中转）。4）自建 vs 第三方——不搞音视频研发的团队直接用声网（Agora）/ 腾讯 TRTC / LiveKit Cloud，自建方案（Mediasoup / SRS）运维成本极高。5）延迟指标分级：优秀 < 100ms（同城 WebRTC P2P）、可用 < 300ms（跨省 SFU）、可接受 < 500ms（全球中转）。","hints":["万人课堂和 1v1 最核心的架构区别是什么——一层分发 vs P2P/SFU","SFU 为什么比 MCU 更适合实时互动场景"],"tags":["系统设计","直播","WebRTC","SFU","低延迟"],"id":5066},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"设计实时特征存储平台","content":"机器学习在线推理场景中，如何设计一个支持毫秒级获取、近实时更新的特征存储（Feature Store）平台？核心挑战是什么？","answer":"特征存储平台是 ML 工程化的核心基础设施，目标是统一离线训练和在线推理的特征一致性。\n\n核心架构：1）存储层——高频特征使用 Redis/Redis Cluster KV 模式（Key=entity_id:feature_name），批处理特征使用 HBase/Cassandra 列式存储支持范围扫描。Embedding 类特征使用专用向量数据库（FAISS/Milvus）。2）数据管道——离线特征通过 Spark 批量计算写入 KV 存储；实时特征通过 Flink 流式计算写入存储。双链路保证特征时效性。3）特征服务——统一 gRPC/HTTP API，封装批量获取逻辑。支持特征聚合（如过去 7 天平均值、滑动窗口计数）。4）特征注册与元数据——特征定义统一注册到元数据中心，包括特征名、类型、计算逻辑、来源表、新鲜度 SLA。5）时间点正确性（Point-in-Time Correctness）——离线训练时需确保使用和在线推理一致的特征切片，避免数据泄露。通过时间戳对齐来解决。\n\n扩展延伸：开源方案对比：Feast（基于 Redis + BigQuery/GCS）、Tecton（企业级完整 Feature Store）、ByteDance 自研（Flink + KV 存储实现毫秒级特征获取）。核心挑战始终是离线/在线一致性——训练时使用的特征时间切片必须严格等于推理时能获取到的特征。","hints":["为什么离线训练和在线推理的特征一致性是个难题","实时特征和批量特征如何保证时间戳对齐"],"tags":["特征工程","机器学习","Feature Store","Redis"],"id":5072},{"category":"system_design_extras","difficulty":"hard","type":"short_answer","title":"设计分布式速率自适应限流系统","content":"如何设计一个能根据系统负载动态调整限流阈值的自适应限流系统？核心指标和算法是什么？","answer":"自适应限流不再依赖静态 QPS 阈值，而是根据系统实时负载指标动态调整允许的请求量。\n\n解析：核心指标：1）CPU 使用率——超过阈值（如 80%）时降低限流阈值。2）平均 RT（响应时间）——RT 突增说明系统过载，触发降流。3）请求成功率/错误率——4xx/5xx 增加时触发降流。4）Inflight 请求数——正在处理中的请求数，类似 TCP 拥塞窗口的概念，Tomcat 的 maxConnections + backlog。5）系统 Load（1min/5min/15min）——Unix Load Average 作为过载信号。\n\n算法：1）Google SRE 的 Concurrency Limiter——基于请求排队深度动态调整并发上限，使用 Gradient 下降算法逼近最优并发数。2）TCP Vegas 风格——比较实际吞吐量和期望吞吐量，偏差大时降流。3）Netflix 自适应限流——监控排队延迟（类似 TCP RTT），当排队延迟超过阈值时降低限流窗口。4）Sentinel 的系统自适应保护——综合 Load、CPU、平均 RT、入口 QPS、并发线程数，通过滑动窗口+规则链计算是否触发限流。\n\n工程实践：Alibaba Sentinel 的 SystemSlot——采集系统指标→根据规则计算最大 QPS→与当前 QPS 对比决定是否限流。自适应阈值有冷却期（刚启动时不限流，等统计数据积累后再生效）。","hints":["静态限流和自适应限流各自的优缺点是什么","Concurrency Limiter 为什么比 QPS Limiter 更适合过载保护"],"tags":["限流","自适应","过载保护","Sentinel"],"id":5073},{"category":"system_design_extras","difficulty":"medium","type":"choice","title":"Saga 事务中的隔离级别与语义锁","content":"在 Saga 分布式事务模式中，以下关于隔离级别与语义锁的描述哪一项是正确的？","options":["A) Saga 天然支持 Read Committed 隔离级别，不需要任何额外的锁机制","B) 语义锁（Semantic Lock）通过给记录加事务状态标记来防止脏读，事务完成后释放","C) 补偿操作（Compensation）天然确保幂等，不需要额外设计","D) Saga 的反向操作（Countermeasure）是指在事务开始时锁定所需资源保证隔离性"],"answer":"B","hints":["Saga 子事务提交后对其他事务是否可见","补偿操作天然幂等吗？需要哪些额外设计"],"tags":["分布式事务","Saga","隔离级别","语义锁"],"id":5074},{"category":"system_design_extras","difficulty":"medium","type":"fill_in_blank","title":"分布式系统中 Exactly-Once 投递的关键机制","content":"消息队列实现 Exactly-Once 语义需要生产者和消费者两端配合。生产者端通过___（机制）确保消息不丢失不重复；消费者端通过___（机制）确保幂等消费；Broker 端通过___（机制）确保消息持久化不丢。在 Kafka 中，Exactly-Once 语义通过___（配置参数）和事务 API 共同实现。","answer":"{\"correct\":[[\"事务 ID / 幂等生产者\"],[\"去重表 / 幂等消费者\"],[\"ACK + 刷盘\"],[\"enable.idempotence=true\"]],\"distractors\":[\"消息回调\",\"死信队列\",\"主从复制\",\"acks=all\"]}","hints":["幂等生产者的实现原理是用什么机制去重","Kafka 的 enable.idempotence=true 具体做了哪些保证"],"tags":["消息队列","Exactly-Once","幂等","Kafka"],"id":5075},{"category":"system_design_extras","difficulty":"hard","type":"true_false","title":"缓存与数据库最终一致性保证机制","content":"使用 Cache Aside 模式时，先更新数据库再删除缓存的策略在任何并发情况下都不会出现缓存与数据库不一致的问题。","answer":"错误。解析：Cache Aside 模式（先写 DB 再删缓存）在极端并发场景下仍然可能出现不一致。具体场景：线程 A 更新数据库（写新值）→ 线程 B 读缓存（缓存未命中）→ 线程 B 从数据库读到旧值（因为 A 的事务未提交或其他延迟）→ 线程 B 将旧值写入缓存 → 线程 A 删除缓存。最终结果是缓存中保留了旧值。解决方案：1）延迟双删——更新 DB 后先删缓存，等待一段时间（如 500ms）再删一次。2）设置缓存过期时间——即使出现不一致也会自动恢复。3）使用 CDC（Canal binlog）+ MQ——订阅 binlog 变更后异步删除/更新缓存，保证最终一致。4）强一致方案——更新时加分布式锁，保证读写串行化。终极方案：使用 Read-Through/Lazy-Propagation + TTL，接受短时间的不一致窗口。","hints":["为什么先更新数据库再删缓存仍然会出现不一致","延迟双删的等待时长如何确定"],"tags":["缓存一致性","Cache Aside","延迟双删","CDC"],"options":["正确","错误"],"id":5076}];
